/* BTNavigationMenu — Figma 2968-2895 (D-NavigationMenu).
   All colours via @btech/tokens CSS vars — no hex fallbacks.
   Shared between Vue and React implementations. */

/* ── Root ─────────────────────────────────────────────────────────── */

.bt-nav-menu {
  display: flex;
  align-items: center;
  width: 100%;
  background: var(--bg-primary);
  border-block-end: 1px solid var(--border-primary);
  padding: var(--space-sm) 24px;
  gap: var(--space-3xl);
  box-sizing: border-box;
}

/* ── Logo ─────────────────────────────────────────────────────────── */

.bt-nav-menu__logo {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  max-width: 107px;
  height: 40px;
}

/* ── Center section — nav items (menu type) ─────────────────────── */

.bt-nav-menu__center {
  display: flex;
  align-items: center;
  flex: 1;
  gap: var(--space-xs);
  min-width: 0;
}

/* ── Trailing section — search + profile ─────────────────────────── */

.bt-nav-menu__trailing {
  display: flex;
  align-items: center;
  gap: var(--space-lg);
  flex-shrink: 0;
}

/* ── Tab-style combined section (BTTabs + search, right-aligned) ─── */

.bt-nav-menu__tabs-section {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  flex: 1;
  gap: var(--space-lg);
  min-width: 0;
}

/* ── Tab-style / segmented — items with filled pill active ──────── */

.bt-nav-menu__tabs-section--segmented {
  gap: var(--space-xs);
}

.bt-nav-menu__tabs-section--segmented .bt-nav-menu-item--active {
  background: var(--color-brand-primary);
  color: var(--text-inverse);
  font-weight: 700;
}

.bt-nav-menu__tabs-section--segmented .bt-nav-menu-item--active:hover:not(.bt-nav-menu-item--disabled) {
  background: var(--color-brand-primary-bold);
  color: var(--text-inverse);
}

/* ── Search wrapper ─────────────────────────────────────────────── */

.bt-nav-menu__search {
  width: 200px;
  flex-shrink: 0;
}

/* ── Nav item (TabMenubar Text Only) ────────────────────────────── */

.bt-nav-menu-item {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: var(--space-sm) var(--space-md);
  border-radius: var(--radius-rd);
  cursor: pointer;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  line-height: var(--typography-line-height-xs);
  font-weight: 500;
  color: var(--text-secondary);
  background: transparent;
  border: none;
  outline: none;
  white-space: nowrap;
  user-select: none;
  /* Transition background + color + font-weight together */
  transition: background-color 0.15s ease, color 0.15s ease;
}

/* Hover (inactive): subtle bg + text turns primary */
.bt-nav-menu-item:hover:not(.bt-nav-menu-item--disabled):not(.bt-nav-menu-item--active) {
  background: var(--bg-subtle);
  color: var(--color-brand-primary);
}

/* Active: text color primary + bold — no background fill */
.bt-nav-menu-item--active {
  color: var(--color-brand-primary);
  font-weight: 700;
}

/* Active focus ring */
.bt-nav-menu-item:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
}

.bt-nav-menu-item--disabled {
  color: var(--text-disabled);
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Inline icons inside nav items ─────────────────────────────── */
.bt-nav-menu-item > svg {
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

/* ── Profile ──────────────────────────────────────────────────────── */

.bt-nav-menu__profile {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  width: 140px;
  flex-shrink: 0;
  cursor: pointer;
  border-radius: var(--radius-sm);
  padding: var(--space-xs) var(--space-sm);
  background: transparent;
  border: none;
  outline: none;
  text-align: start;
  transition: background-color 0.15s ease;
}

.bt-nav-menu__profile:hover {
  background: var(--bg-subtle);
}

.bt-nav-menu__profile:hover .bt-nav-menu__profile-chevron {
  color: var(--color-brand-primary);
}

.bt-nav-menu__profile:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 2px;
}

.bt-nav-menu__profile-text {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  gap: var(--space-2xs);
}

.bt-nav-menu__profile-name {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  line-height: var(--typography-line-height-sm);
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bt-nav-menu__profile-desc {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bt-nav-menu__profile-chevron {
  width: 16px;
  height: 16px;
  color: var(--text-secondary);
  flex-shrink: 0;
}

/**
 * BTNavigationMenu — horizontal top navigation bar for desktop layouts.
 * Figma: node 2968-2895 (D-NavigationMenu).
 * Web only — no Flutter implementation.
 *
 * Composes:
 *   - BTAvatar       (profile avatar, size="sm")
 *   - BTInputSearch  (search field, when searchValue prop is provided)
 *   - BTTabs         (tab-style variant, variant="line")
 *
 * @example
 * ```tsx
 * const [activeId, setActiveId] = useState('home');
 * <BTNavigationMenu
 *   type="menu"
 *   activeId={activeId}
 *   items={navItems}
 *   searchValue={searchQuery}
 *   profile={{ avatar: { name: 'John Doe' }, name: 'John Doe', description: 'Admin' }}
 *   logo={<img src="/logo.svg" alt="App" />}
 *   onActiveIdChange={setActiveId}
 *   onSearch={setSearchQuery}
 *   onProfileClick={openProfileMenu}
 * />
 * ```
 */
import './BTNavigationMenu.css';
import { BTAvatar } from '../../molecules/Avatar/BTAvatar.js';
import { BTInputSearch } from '../../molecules/Input/Search/BTInputSearch.js';
import { BTTabs } from '../../molecules/Tabs/BTTabs.js';
import type { BTNavigationMenuProps, BTNavigationMenuItem } from './BTNavigationMenu.types.js';

export function BTNavigationMenu({
  type = 'menu',
  items = [],
  activeId,
  profile,
  tabs = [],
  activeTabIndex = 0,
  tabVariant = 'line',
  searchValue,
  logo,
  center,
  trailing,
  profileSlot,
  onItemClick,
  onActiveIdChange,
  onTabClick,
  onActiveTabIndexChange,
  onProfileClick,
  onSearch,
}: BTNavigationMenuProps) {
  const hasSearch = searchValue !== undefined;

  function handleItemClick(item: BTNavigationMenuItem) {
    if (item.disabled) return;
    onActiveIdChange?.(item.id);
    onItemClick?.(item);
  }

  function handleTabClick(index: number) {
    onActiveTabIndexChange?.(index);
    onTabClick?.(index);
  }

  return (
    <header className="bt-nav-menu" role="banner">

      {/* ── Logo ─────────────────────────────────────────────── */}
      {logo && <div className="bt-nav-menu__logo">{logo}</div>}

      {/* ── Menu type ──────────────────────────────────────────── */}
      {type === 'menu' && (
        <>
          {/* Center: nav items + optional extra */}
          <nav className="bt-nav-menu__center" aria-label="Navigation">
            {items.map((item) => (
              <button
                key={item.id}
                type="button"
                className={[
                  'bt-nav-menu-item',
                  item.id === activeId ? 'bt-nav-menu-item--active' : '',
                  item.disabled ? 'bt-nav-menu-item--disabled' : '',
                ]
                  .filter(Boolean)
                  .join(' ')}
                aria-current={item.id === activeId ? 'page' : undefined}
                disabled={item.disabled}
                onClick={() => handleItemClick(item)}
              >
                {item.startIcon && (
                  <svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
                    <path d={item.startIcon} />
                  </svg>
                )}
                {item.label}
              </button>
            ))}
            {center}
          </nav>

          {/* Trailing: optional slot + search + profile */}
          {(trailing || hasSearch || profile || profileSlot) && (
            <div className="bt-nav-menu__trailing">
              {trailing}

              {hasSearch && (
                <div className="bt-nav-menu__search">
                  <BTInputSearch
                    value={searchValue ?? ''}
                    onChange={v => onSearch?.(v)}
                    onSearch={q => onSearch?.(q)}
                    placeholder="Search..."
                  />
                </div>
              )}

              {/*
                profileSlot takes precedence — use for dynamic content:
                BTPopover, BTDropdownList, fully custom trigger, etc.
                Falls back to the fixed profile button from the `profile` prop.
              */}
              {profileSlot ?? (profile && (
                <button
                  type="button"
                  className="bt-nav-menu__profile"
                  aria-label="Open profile menu"
                  onClick={onProfileClick}
                >
                  <BTAvatar item={profile.avatar} size="sm" />
                  <div className="bt-nav-menu__profile-text">
                    <span className="bt-nav-menu__profile-name">{profile.name}</span>
                    {profile.description && (
                      <span className="bt-nav-menu__profile-desc">{profile.description}</span>
                    )}
                  </div>
                  {/* Chevron down (Figma: chevron_down 16 px) */}
                  <svg
                    className="bt-nav-menu__profile-chevron"
                    viewBox="0 0 16 16"
                    fill="none"
                    aria-hidden="true"
                  >
                    <path
                      d="M4 6L8 10L12 6"
                      stroke="currentColor"
                      strokeWidth="1.5"
                      strokeLinecap="round"
                      strokeLinejoin="round"
                    />
                  </svg>
                </button>
              ))}
            </div>
          )}
        </>
      )}

      {/* ── Tab-style type ─────────────────────────────────────── */}
      {type === 'tab-style' && (
        <div
          className={[
            'bt-nav-menu__tabs-section',
            tabVariant === 'segmented' ? 'bt-nav-menu__tabs-section--segmented' : '',
          ].filter(Boolean).join(' ')}
        >
          {/* line → BTTabs with underline indicator */}
          {tabVariant === 'line' && tabs.length > 0 && (
            <BTTabs
              variant="line"
              tabs={tabs}
              activeIndex={activeTabIndex}
              onActiveIndexChange={handleTabClick}
            />
          )}

          {/* segmented → individual buttons with filled pill active */}
          {tabVariant === 'segmented' && tabs.map((tab, index) => (
            <button
              key={index}
              type="button"
              className={[
                'bt-nav-menu-item',
                index === activeTabIndex ? 'bt-nav-menu-item--active' : '',
                tab.disabled ? 'bt-nav-menu-item--disabled' : '',
              ].filter(Boolean).join(' ')}
              disabled={tab.disabled}
              onClick={() => handleTabClick(index)}
            >
              {tab.startIcon && (
                <svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
                  <path d={tab.startIcon} />
                </svg>
              )}
              {tab.label}
            </button>
          ))}

          {hasSearch && (
            <div className="bt-nav-menu__search">
              <BTInputSearch
                value={searchValue ?? ''}
                onChange={v => onSearch?.(v)}
                onSearch={q => onSearch?.(q)}
                placeholder="Search..."
              />
            </div>
          )}
        </div>
      )}

    </header>
  );
}

BTNavigationMenu.displayName = 'BTNavigationMenu';

/**
 * BTNavigationMenu public API types.
 *
 * Figma: node 2968-2895 (D-NavigationMenu).
 * Web only — no Flutter implementation.
 */
import type { BTAvatarItem } from '../../molecules/Avatar/BTAvatar.types.js';
import type { BTTabItem, BTTabsVariant } from '../../molecules/Tabs/BTTabs.types.js';

export type BTNavigationMenuType = 'menu' | 'tab-style';

/** A single nav item in the menu bar. */
export interface BTNavigationMenuItem {
  /** Unique identifier for this item. */
  id: string;
  /** Label text displayed in the nav item. */
  label: string;
  /** Whether this item is non-interactive. @default false */
  disabled?: boolean;
  /**
   * SVG path `d` attribute for an optional leading icon (24×24 viewBox).
   * When provided, a 16×16 SVG icon is rendered before the label.
   */
  startIcon?: string;
}

/** Profile section data — shown at the trailing end of menu-type nav. */
export interface BTNavigationMenuProfile {
  /** Avatar payload — renders as BTAvatar size="sm". */
  avatar: BTAvatarItem;
  /** Primary name line (14 px bold). */
  name: string;
  /** Secondary description line (12 px, e.g. role or email). */
  description?: string;
}

export interface BTNavigationMenuProps {
  /**
   * Visual layout variant.
   * - `'menu'`       — logo | nav items + optional extra | search + profile
   * - `'tab-style'`  — logo | BTTabs line + optional search (right-aligned)
   * @default 'menu'
   */
  type?: BTNavigationMenuType;

  // ── menu type ─────────────────────────────────────────────────────

  /**
   * Navigation items for the `menu` variant.
   * Each renders as a pill text item (TabMenubar Text Only).
   */
  items?: BTNavigationMenuItem[];

  /** ID of the currently active nav item (`menu` variant). */
  activeId?: string;

  /** Profile section shown at the trailing end (`menu` variant). */
  profile?: BTNavigationMenuProfile;

  // ── tab-style type ─────────────────────────────────────────────────

  /**
   * Tab items for the `tab-style` variant.
   * Passed directly to `BTTabs`.
   */
  tabs?: BTTabItem[];

  /**
   * Active tab index for the `tab-style` variant.
   * @default 0
   */
  activeTabIndex?: number;

  /**
   * BTTabs variant for the `tab-style` layout.
   * - `'line'`      — underline indicator (default, matches Figma)
   * - `'segmented'` — filled pill tray
   * @default 'line'
   */
  tabVariant?: BTTabsVariant;

  // ── shared ─────────────────────────────────────────────────────────

  /**
   * When provided, shows a `BTInputSearch` in the trailing section.
   * Pass `''` to show the field with no pre-filled value.
   */
  searchValue?: string;

  // ── slots ──────────────────────────────────────────────────────────

  /** Logo area — any ReactNode (img, svg, custom component). */
  logo?: React.ReactNode;
  /** Extra content after nav items in the center section (menu variant). */
  center?: React.ReactNode;
  /** Extra content before search/profile in the trailing section (menu variant). */
  trailing?: React.ReactNode;
  /**
   * Dynamic profile area — accepts any ReactNode (BTPopover, BTDropdownList,
   * a fully custom trigger, etc.). When provided, renders instead of the fixed
   * profile button from the `profile` data prop.
   * @example
   * ```tsx
   * profileSlot={
   *   <BTPopover content={<BTDropdownList items={profileItems} />}>
   *     <button className="bt-nav-menu__profile">...</button>
   *   </BTPopover>
   * }
   * ```
   */
  profileSlot?: React.ReactNode;

  // ── callbacks ──────────────────────────────────────────────────────

  /** Called when a nav item is clicked (`menu` variant). */
  onItemClick?: (item: BTNavigationMenuItem) => void;
  /** Called when active nav item changes — use for controlled `activeId`. */
  onActiveIdChange?: (id: string) => void;
  /** Called when a tab is selected (`tab-style` variant). */
  onTabClick?: (index: number) => void;
  /** Called when active tab index changes — use for controlled `activeTabIndex`. */
  onActiveTabIndexChange?: (index: number) => void;
  /** Called when the profile button is clicked. */
  onProfileClick?: () => void;
  /** Called on search input change or submit. */
  onSearch?: (value: string) => void;
}

export type { BTAvatarItem, BTTabItem, BTTabsVariant };
